import{_ as t,c as n,o as i,ag as a}from"./chunks/framework.Bzez9NG9.js";const s="/space/img/sidebar.png",o="/space/img/space-architecture.png",h=JSON.parse('{"title":"SPACE","titleTemplate":"Getting started","description":"","frontmatter":{"outline":"deep","title":"SPACE","titleTemplate":"Getting started"},"headers":[],"relativePath":"doc/index.md","filePath":"doc/index.md"}'),r={name:"doc/index.md"};function l(c,e,d,p,u,m){return i(),n("div",null,e[0]||(e[0]=[a('<h1 id="space-overview" tabindex="-1">SPACE overview <a class="header-anchor" href="#space-overview" aria-label="Permalink to &quot;SPACE overview&quot;">​</a></h1><h2 id="what-is-space" tabindex="-1">What is SPACE? <a class="header-anchor" href="#what-is-space" aria-label="Permalink to &quot;What is SPACE?&quot;">​</a></h2><p>The Succeedium Planning Analytics Cloud Extension (SPACE) helps teams generate automated, interactive TM1 model documentation, audit and trace every change, run and orchestrate Python automation, govern environments with end-to-end version control, and use AI-assisted guidance directly inside IBM Planning Analytics Workspace.</p><p>Because SPACE is embedded directly inside IBM Planning Analytics Workspace (PAW), it works within your existing security model and provides a seamless, governed experience without forcing users to switch between disconnected tools.</p><p>SPACE makes IBM Planning Analytics more transparent, automated, and intelligent—improving model quality, accelerating development cycles, simplifying support, and maintaining full governance across every environment.</p><p><img src="'+s+'" alt="SPACE overview" data-zoomable=""></p><h2 id="key-capabilities" tabindex="-1">Key capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key capabilities&quot;">​</a></h2><ul><li><strong>AI Assistant</strong> – Ask questions about SPACE functionality and connected TM1 models directly inside PAW. The assistant can use SPACE-controlled tools to inspect model objects, including cubes, dimensions, rules and processes, generate documentation, analyze models, investigate logs, review code and assess deployment impact, while respecting SPACE access controls and IBM Planning Analytics permissions.</li><li><strong>Model documentation</strong> – Automatically map cubes, dimensions, rules, and processes into an interactive diagram so teams can understand dependencies without sifting through code.</li><li><strong>Audit &amp; logs</strong> – Centralize TM1 audit, transaction, and message logs in a single searchable interface, allowing even non-admins with proper permissions to investigate issues and satisfy compliance requests.</li><li><strong>Lifecycle management</strong> – Compare and synchronize environments, promote objects through structured releases, and keep a full trace of every deployment for governance and rollback.</li><li><strong>Python integration</strong> – Create, schedule, and monitor Python scripts directly in PAW to automate data flows, calculations, and integrations with external services.</li><li><strong>Git integration</strong> – Link TM1 models to Git repositories for collaborative version control, code review, and full history of every change.</li><li><strong>Security insights</strong> – Trace user access across cubes, dimensions, hierarchies, and cells to explain exactly why a user can or cannot see specific data.</li></ul><h2 id="architecture-and-deployment" tabindex="-1">Architecture and deployment <a class="header-anchor" href="#architecture-and-deployment" aria-label="Permalink to &quot;Architecture and deployment&quot;">​</a></h2><p>SPACE is a containerized application that can run on AWS, Microsoft Azure, Google Cloud Platform, IBM Cloud, or on-premises next to IBM Planning Analytics Local. A single SPACE deployment can connect to multiple TM1 servers, giving administrators a unified control plane for documentation, automation, AI assistance, and lifecycle operations while respecting each server’s native security and permissions.</p><p>Depending on your IBM Planning Analytics architecture, including cloud, private cloud, SaaS, or on-premises environments with SSO, CAM, or other authentication configurations, Succeedium provides a customized welcome kit that covers prerequisites, deployment steps, and installation instructions. Please rely on the welcome kit for your environment when installing SPACE or onboarding new instances.</p><p><img src="'+o+'" alt="SPACE architecture" data-zoomable=""></p><h2 id="roadmap-highlights" tabindex="-1">Roadmap highlights <a class="header-anchor" href="#roadmap-highlights" aria-label="Permalink to &quot;Roadmap highlights&quot;">​</a></h2><ul><li><strong>Workflow automation</strong> – Build ETL-style pipelines that connect TM1 with platforms such as Workday, Salesforce, SAP, Slack, and more to automate business processes end-to-end.</li><li><strong>External AI integrations</strong> – SPACE will expose an MCP server for IBM Planning Analytics (TM1), allowing external AI clients to access selected SPACE capabilities through controlled integration layers while preserving SPACE security, connection access, and IBM Planning Analytics permissions.</li></ul>',14)]))}const y=t(r,[["render",l]]);export{h as __pageData,y as default};
